 * Computes the square-root of the weight matrix.
 *
 * @param m Symmetric, positive-definite (weight) matrix.
 * @return the square-root of the weight matrix.
 */
private RealMatrix squareRoot(RealMatrix m) {
    final EigenDecomposition dec = new EigenDecomposition(m);
    // Work around computation errors in getSquareRoot that can lead to slightly
    // negative eigenvalues with very small absolute values when computing the
    // square root of the matrix. These can result in exceptions being thrown
    // even for very legitimate cases.
    final double[] eigenValues = dec.getRealEigenvalues();
    final double[] modifiedEigenValues = new double[eigenValues.length];
    boolean hasNegligibleNegativeEigenvalue = false;
    for (int i = 0; i < eigenValues.length; i++) {
